// Process synergy analysis and generate comprehensive recommendations
const combinationConfig = $('Configure Combination Analysis').first();
const audienceAnalysis = $('Analyze Audience Overlap').first();
const collaborationIdeas = $('Generate Collaboration Ideas').first();
const revenueStrategies = $('Develop Revenue Strategies').first();

// Extract AI responses
const audienceInsights = audienceAnalysis.choices?.[0]?.message?.content || '';
const collaborationSuggestions = collaborationIdeas.content?.[0]?.text || '';
const revenueRecommendations = revenueStrategies.choices?.[0]?.message?.content || '';

// Parse recommendations into structured format
function parseRecommendations(text, category) {
  const lines = text.split('\n').filter(line => line.trim());
  const recommendations = [];

  lines.forEach(line => {
    if (line.includes('•') || line.includes('-') || /^\d+\./.test(line.trim())) {
      const cleanLine = line.replace(/^[•\-\d\.\s]+/, '').trim();
      if (cleanLine.length > 10) {
        recommendations.push({
          category,
          recommendation: cleanLine,
          priority: line.toLowerCase().includes('high') || line.toLowerCase().includes('priority') ? 'high' : 'medium',
          implementation_effort: estimateImplementationEffort(cleanLine),
          expected_impact: estimateExpectedImpact(cleanLine, category)
        });
      }
    }
  });

  return recommendations;
}

function estimateImplementationEffort(recommendation) {
  const lowEffortKeywords = ['mention', 'share', 'post', 'link', 'tag'];
  const highEffortKeywords = ['develop', 'create', 'build', 'design', 'launch'];

  const text = recommendation.toLowerCase();
  if (lowEffortKeywords.some(keyword => text.includes(keyword))) return 'low';
  if (highEffortKeywords.some(keyword => text.includes(keyword))) return 'high';
  return 'medium';
}

function estimateExpectedImpact(recommendation, category) {
  const impactMap = {
    audience: { high: 0.25, medium: 0.15, low: 0.05 },
    collaboration: { high: 0.20, medium: 0.12, low: 0.08 },
    revenue: { high: 0.30, medium: 0.18, low: 0.10 }
  };

  const text = recommendation.toLowerCase();
  const categoryKey = category.includes('audience') ? 'audience' : 
                     category.includes('collaboration') ? 'collaboration' : 'revenue';

  if (text.includes('significant') || text.includes('major') || text.includes('substantial')) {
    return impactMap[categoryKey].high;
  } else if (text.includes('moderate') || text.includes('good') || text.includes('solid')) {
    return impactMap[categoryKey].medium;
  }
  return impactMap[categoryKey].low;
}

// Parse all recommendations
const allRecommendations = [
  ...parseRecommendations(audienceInsights, 'audience_development'),
  ...parseRecommendations(collaborationSuggestions, 'content_collaboration'),
  ...parseRecommendations(revenueRecommendations, 'revenue_optimization')
];

// Prioritize recommendations
const prioritizedRecommendations = allRecommendations
  .sort((a, b) => {
    // Sort by priority first, then by expected impact
    if (a.priority !== b.priority) {
      return a.priority === 'high' ? -1 : 1;
    }
    return b.expected_impact - a.expected_impact;
  })
  .slice(0, 10); // Top 10 recommendations

// Generate implementation roadmap
const implementationRoadmap = {
  immediate_actions: prioritizedRecommendations
    .filter(r => r.implementation_effort === 'low' && r.priority === 'high')
    .slice(0, 3),
  short_term_goals: prioritizedRecommendations
    .filter(r => r.implementation_effort === 'medium')
    .slice(0, 4),
  long_term_projects: prioritizedRecommendations
    .filter(r => r.implementation_effort === 'high')
    .slice(0, 3)
};

// Calculate synergy potential metrics
const synergyMetrics = {
  audience_growth_potential: Math.round(combinationConfig.synergy_score.individual_scores.audience_overlap * 0.3),
  revenue_increase_potential: Math.round(combinationConfig.synergy_score.individual_scores.revenue_synergy * 0.25),
  content_efficiency_gain: Math.round(combinationConfig.synergy_score.individual_scores.platform_overlap * 0.4),
  overall_synergy_value: combinationConfig.synergy_score.overall_score
};

// Generate success tracking KPIs
const trackingKPIs = {
  audience_metrics: {
    cross_brand_traffic: { target: '15%', timeframe: '30 days' },
    audience_overlap_growth: { target: '25%', timeframe: '60 days' },
    cross_platform_engagement: { target: '20%', timeframe: '30 days' }
  },
  content_metrics: {
    collaboration_content_performance: { target: '30% above average', timeframe: '30 days' },
    cross_mention_engagement: { target: '5% CTR', timeframe: 'ongoing' },
    shared_content_reach: { target: '40% increase', timeframe: '45 days' }
  },
  revenue_metrics: {
    cross_brand_conversions: { target: '2%', timeframe: '60 days' },
    shared_affiliate_revenue: { target: '20% increase', timeframe: '90 days' },
    customer_lifetime_value: { target: '$150', timeframe: '180 days' }
  }
};

return {
  brand_combination: {
    brands: combinationConfig.brand_combination.brands,
    overlap_potential: combinationConfig.brand_combination.overlap_potential,
    priority: combinationConfig.brand_combination.priority
  },
  synergy_analysis: {
    audience_insights: audienceInsights.substring(0, 500),
    collaboration_suggestions: collaborationSuggestions.substring(0, 500),
    revenue_recommendations: revenueRecommendations.substring(0, 500)
  },
  synergy_score: combinationConfig.synergy_score,
  synergy_metrics: synergyMetrics,
  recommendations: {
    all_recommendations: allRecommendations,
    prioritized_recommendations: prioritizedRecommendations,
    implementation_roadmap: implementationRoadmap
  },
  tracking_kpis: trackingKPIs,
  analysis_timestamp: combinationConfig.analysis_timestamp,
  next_review_date: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString() // Review in 7 days
};
